from src.models import Item, Order

def calculate_total(items):
    return sum(item.price for item in items)

def validate_item(item_data):
    return Item(name=item_data["name"], price=item_data["price"])

def process_order(order_id, item_data):
    items = [validate_item(data) for data in item_data]
    calculate_total(items)
    order = Order(order_id=order_id, items=items, status="processed")
    return order

from src.services import process_order

def main():
    test_items = [
        {'name': 'Item 1', 'price': 10.0},
        {'name': 'Item 2', 'price': 20.0},
        {'name': 'Item 3', 'price': 0.0}
    ]
    order = process_order('ORD-001', test_items)
    print(f"Order processed successfully: {order}")

if __name__ == '__main__':
    main()

